SELECT COUNT(*) AS lockout_count
FROM account_lockouts
WHERE reason = 'Exceeded maximum login attempts';

SELECT last_login
FROM users
ORDER BY last_login DESC;

SELECT username, last_login
FROM users
WHERE is_active = 1 AND last_login < DATE('now', '-30 days');

SELECT AVG(strength_score) AS average_strength
FROM password_strength
WHERE user_id = 1;

SELECT user_id, AVG(strength_score) AS average_strength
FROM password_strength
GROUP BY user_id;
